describe("Response class",()=>{it("should construct a new Response object with default values",()=>{let e=new Response;expect(e.status).toEqual(200),expect(e.statusText).toEqual("OK"),expect(e.headers instanceof Headers).toBeTruthy(),expect(e.body).toEqual(void 0),expect(e.redirected).toBeFalsy()}),it("should set the status and statusText to the provided values",()=>{let e=new Response(null,{status:404,statusText:"Not Found"});expect(e.status).toEqual(404),expect(e.statusText).toEqual("Not Found")}),it("should set the headers to the provided value",()=>{let e=new Headers({"Content-Type":"application/json"}),t=new Response(null,{headers:e});expect(t.headers.get("Content-Type")).toStrictEqual("application/json")}),it("should set the body to the provided value",async()=>{let e="Hello, world!",t=new Response(e);expect(t.bodyUsed).toBeFalsy(),expect(await t.text()).toStrictEqual(e),expect(t.bodyUsed).toBeTruthy()}),it("should set the body to a Blob if a Blob is provided",async()=>{let e=new Blob(["Hello, world!"],{type:"text/plain"}),t=new Response(e);expect(t.bodyUsed).toBeFalsy(),expect(await t.text()).toEqual("Hello, world!"),expect(t.bodyUsed).toBeTruthy()}),it("should set the body to a JSON object if a JSON object is provided",async()=>{let e={key:"value"},t=new Response(JSON.stringify(e),{headers:{"Content-Type":"application/json"}});expect(t.bodyUsed).toBeFalsy(),expect(await t.json()).toStrictEqual(e),expect(t.bodyUsed).toBeTruthy()}),it("should set the body to a bytes object if a bytes object is provided",async()=>{let e=new Uint8Array([1,2,3]),t=new Response(e);expect(t.bodyUsed).toBeFalsy(),expect(await t.bytes()).toStrictEqual(e),expect(t.bodyUsed).toBeTruthy()}),it("should clone the response with the clone() method",()=>{let e=new Response("Original response"),t=e.clone();expect(e.body).toEqual(t.body),expect(e.url).toEqual(t.url),expect(e.status).toEqual(t.status),expect(e.statusText).toEqual(t.statusText),expect(e.headers).toEqual(t.headers),expect(e.type).toEqual(t.type),expect(e.ok).toEqual(t.ok),expect(e.bodyUsed).toEqual(t.bodyUsed),expect(e.redirected).toEqual(t.redirected)}),it("should create a Response object with an ok status for status codes in the range 200-299",()=>{let e=new Response("Success",{status:204});expect(e.ok).toBeTruthy()}),it("should create a Response object with not-ok status for status codes outside the range 200-299",()=>{let e=new Response("Error",{status:404});expect(!e.ok).toBeTruthy()}),it("should be returned specified values in error static function",()=>{let e=Response.error();expect(e.status).toEqual(0),expect(e.statusText).toEqual(""),expect(e.headers instanceof Headers).toBeTruthy(),expect(e.body).toEqual(void 0),expect(e.type).toEqual("error")}),it("should be returned specified values in redirect static function called single param",()=>{let e="http://localhost/",t=Response.redirect(e);expect(t.status).toEqual(302),expect(t.headers.get("location")).toEqual(e)}),it("should be returned specified values in redirect static function called double param",()=>{let e="http://localhost/",t=Response.redirect(e,301);expect(t.status).toEqual(301),expect(t.headers.get("location")).toEqual(e)}),it("should be returned specified values in json static function called single param",()=>{let e={some:"data",more:"information"},t=Response.json(JSON.stringify(e));expect(t.status).toEqual(200),t.json().then(s=>{expect(s).toStrictEqual(e)})}),it("should be returned specified values in json static function called double param",()=>{let e={some:"data",more:"information"},t=Response.json(JSON.stringify(e),{status:200,statusText:"SuperSmashingGreat!",headers:{"Content-Type":"application/json"}});expect(t.status).toEqual(200),expect(t.statusText).toEqual("SuperSmashingGreat!"),t.json().then(s=>{expect(s).toStrictEqual(e)})}),it("returns JSON with 200 by default",async()=>{let e={message:"pong"},t=Response.json(e);expect(t.status).toEqual(200),expect(t.headers.get("content-type")).toEqual("application/json;charset=UTF-8"),expect(await t.json()).toEqual(e)}),it("serializes JSON body to text",async()=>{let e={message:"pong"},t=Response.json(e);expect(t.status).toEqual(200),expect(t.headers.get("content-type")).toEqual("application/json;charset=UTF-8"),expect(await t.text()).toEqual(JSON.stringify(e))}),it("supports custom status and statusText",async()=>{let e={some:"data",more:"information"},t=Response.json(e,{status:307,statusText:"Temporary Redirect"});expect(t.status).toEqual(307),expect(t.statusText).toEqual("Temporary Redirect"),expect(t.headers.get("content-type")).toEqual("application/json;charset=UTF-8"),expect(await t.text()).toEqual(JSON.stringify(e))})});
